                              <FormDescription className="text-xs">
                                ↳ Potential customer with a verification badge.
                              </FormDescription>
                            </div>
                            {fieldState.error && (
                              <FormMessage>
                                {fieldState.error.message}
                              </FormMessage>
                            )}
                          </FormItem>
