                      />

                      <Controller
                        control={form.control}
                        name="unverified"
                        render={({ field, fieldState }) => (
                          <FormItem className="flex flex-row items-start gap-3 space-y-0">
                            <FormControl>
                              <Checkbox
                                checked={field.value}
                                onCheckedChange={field.onChange}
                                disabled={isLoading}
                              />
                            </FormControl>
                            <div className="grid gap-0.5">
                              <FormLabel className="text-sm font-medium">
                                Unverified
                              </FormLabel>
                              <FormDescription className="text-xs">
                                ↳ Potential customer without a verification
                                badge.
                              </FormDescription>
                            </div>
                            {fieldState.error && (
                              <FormMessage>
                                {fieldState.error.message}
                              </FormMessage>
                            )}
                          </FormItem>
                        )}
                      />
                    </div>
                  </div>

                  <Separator />

                  {/* User Fields */}
                  <section className="space-y-4 px-4 @container">
                    <div className="grid grid-cols-1 gap-x-2 gap-y-4 @sm:grid-cols-2 @md:grid-cols-3 @lg:grid-cols-4">
                      <Controller
                        control={form.control}
                        name="from"
                        render={({ field, fieldState }) => (
                          <FormItem>
                            <FormLabel className="text-sm font-medium">
                              From
                            </FormLabel>
                            <FormControl>
                              <Input
                                size="sm"
                                placeholder="e.g., elonmusk"
                                disabled={isLoading}
                                {...field}
                              />
                            </FormControl>
                            <FormDescription className="ml-3 text-xs text-muted-foreground">
                              ↳ Posts from a specific @username.
                            </FormDescription>
                            {fieldState.error && (
                              <FormMessage>
                                {fieldState.error.message}
                              </FormMessage>
                            )}
                          </FormItem>
                        )}
                      />

                      <Controller
                        control={form.control}
                        name="to"
                        render={({ field, fieldState }) => (
                          <FormItem>
                            <FormLabel className="text-sm font-medium">
                              To
                            </FormLabel>
                            <FormControl>
                              <Input
                                size="sm"
                                placeholder="e.g., elonmusk"
                                disabled={isLoading}
                                {...field}
                              />
                            </FormControl>
                            <FormDescription className="ml-3 text-xs text-muted-foreground">
                              ↳ Posts replying to a specific @username.
                            </FormDescription>
                            {fieldState.error && (
                              <FormMessage>
                                {fieldState.error.message}
                              </FormMessage>
                            )}
                          </FormItem>
                        )}
                      />

                      <Controller
                        control={form.control}
                        name="mention"
                        render={({ field, fieldState }) => (
                          <FormItem>
                            <FormLabel className="text-sm font-medium">
                              Mention
                            </FormLabel>
                            <FormControl>
                              <Input
                                size="sm"
                                placeholder="e.g., elonmusk"
                                disabled={isLoading}
                                {...field}
                              />
                            </FormControl>
                            <FormDescription className="ml-3 text-xs text-muted-foreground">
                              ↳ Posts mentioning a specific @username.
                            </FormDescription>
                            {fieldState.error && (
                              <FormMessage>
                                {fieldState.error.message}
                              </FormMessage>
                            )}
                          </FormItem>
                        )}
                      />

                      <Controller
                        control={form.control}
                        name="list"
                        render={({ field, fieldState }) => (
                          <FormItem>
                            <FormLabel className="text-sm font-medium">
                              List
                            </FormLabel>
                            <FormControl>
                              <Input
                                size="sm"
                                placeholder="e.g., esa/astronauts"
                                disabled={isLoading}
                                {...field}
                              />
                            </FormControl>
                            <FormDescription className="ml-3 text-xs text-muted-foreground">
                              ↳ Posts from members of a specified public list
                              (by list ID or slug).
                            </FormDescription>
                            {fieldState.error && (
                              <FormMessage>
                                {fieldState.error.message}
                              </FormMessage>
                            )}
                          </FormItem>
                        )}
                      />
                    </div>
                  </section>

                  <Separator />

                  {/* Exclude users (combobox) */}
                  <section className="space-y-2 px-4">
                    <div>
                      <h3 className="text-sm font-medium">Exclude users.</h3>
                      <p className="mt-1.5 text-xs text-muted-foreground">
                        ↳ Hide posts from selected handles.
                      </p>
                    </div>

                    {isMobile ? (
                      <Drawer>
                        <DrawerTrigger asChild>
                          <Button
                            variant="outline"
                            size="sm"
                            className="justify-start"
                          >
                            <AddIcon className="fill-current" />
                            Add users
                          </Button>
                        </DrawerTrigger>
                        <DrawerContent>
                          <div className="mt-4 border-t">
                            <Command>
                              <CommandInput
                                placeholder="Search or type a handle..."
                                onKeyDown={(e) => {
                                  if (e.key === "Enter") {
                                    const target = e.target as HTMLInputElement;
                                    const val = target.value || "";
                                    if (val.trim()) {
                                      addExcludeUser(val);
                                      target.value = "";
                                    }
                                    e.preventDefault();
                                  }
                                }}
                              />
                              <CommandList>
                                <CommandEmpty>No results.</CommandEmpty>
                                <CommandGroup>
                                  {safeSuggestions.map((u) => {
                                    const selected = (
                                      excludeUsers || []
                                    ).includes(u);
                                    return (
                                      <CommandItem
                                        key={u}
                                        value={u}
                                        onSelect={(v) => {
                                          toggleExcludeUser(v);
                                        }}
                                      >
                                        @{u}
                                        <CheckIcon
                                          className={cn(
                                            "ml-auto h-4 w-4",
                                            selected
                                              ? "opacity-100"
                                              : "opacity-0"
                                          )}
                                        />
                                      </CommandItem>
                                    );
                                  })}
                                </CommandGroup>
                              </CommandList>
                            </Command>
                          </div>
                        </DrawerContent>
                      </Drawer>
                    ) : (
                      <Popover>
                        <PopoverTrigger asChild>
                          <Button
                            variant="outline"
                            size="sm"
                            className="justify-between"
                          >
                            <AddIcon className="fill-current" />
                            Add users
                          </Button>
                        </PopoverTrigger>
                        <PopoverContent className="w-[260px] p-0" align="start">
                          <Command>
                            <CommandInput
                              placeholder="Search or type a handle..."
                              onKeyDown={(e) => {
                                if (e.key === "Enter") {
                                  const target = e.target as HTMLInputElement;
                                  const val = target.value || "";
                                  if (val.trim()) {
                                    addExcludeUser(val);
                                    target.value = "";
                                  }
                                  e.preventDefault();
                                }
                              }}
                            />
                            <CommandList>
                              <CommandEmpty>No results.</CommandEmpty>
                              <CommandGroup>
                                {fullSuggestions.map((u) => {
                                  const selected = (
                                    excludeUsers || []
                                  ).includes(u);
                                  return (
                                    <CommandItem
                                      key={u}
                                      value={u}
                                      onSelect={(v) => {
                                        toggleExcludeUser(v);
                                      }}
                                    >
                                      @{u}
                                      <Check
                                        className={cn(
                                          "ml-auto h-4 w-4",
                                          selected ? "opacity-100" : "opacity-0"
                                        )}
                                      />
                                    </CommandItem>
                                  );
                                })}
                              </CommandGroup>
                            </CommandList>
                          </Command>
                        </PopoverContent>
                      </Popover>
                    )}

                    {/* Chips */}
                    {excludeUsers?.length > 0 && (
                      <div className="flex flex-wrap items-center gap-1">
                        {excludeUsers.map((u: string) => (
                          <Badge
                            key={u}
                            variant="outline"
                            className="flex items-center gap-1 font-mono"
                          >
                            @{u}
                            <Button
                              variant="ghost"
                              size="xsIcon"
                              onClick={() => removeExcludeUser(u)}
                              aria-label={`Remove ${u}`}
                            >
                              <CloseIcon className="fill-current" />
                            </Button>
                          </Badge>
                        ))}
                        <Button
                          variant="ghost"
                          size="xs"
                          onClick={() =>
                            form.setValue("excludeUsers", [], {
                              shouldDirty: true,
                            })
                          }
                        >
                          Clear all
                        </Button>
                      </div>
                    )}
                  </section>
                </div>
              </TabsContent>

              {/* Date Tab */}
              <TabsContent value="date" className="mt-0">
                <div className="space-y-4">
                  {/* No Range Section */}
                  <div className="space-y-1.5 px-4">
                    <div>
                      <h3 className="text-sm font-medium">No range.</h3>
                      <p className="mt-1.5 text-xs text-muted-foreground">
                        ↳ See all posts without any date filter.
                      </p>
                    </div>

                    <Controller
                      control={form.control}
                      name="dateRange"
                      render={({ field }) => (
                        <FormItem className="flex flex-row items-start gap-3 space-y-0">
                          <FormControl>
                            <RadioGroup
                              value={field.value}
                              onValueChange={field.onChange}
                              disabled={isLoading}
                            >
                              <div className="flex items-start space-x-2">
                                <RadioGroupItem
                                  value="all_time"
                                  id="all_time"
                                />
                                <div className="grid gap-0.5">
                                  <FormLabel
                                    htmlFor="all_time"
                                    className="text-sm font-medium"
                                  >
                                    All time
                                  </FormLabel>
                                  <FormDescription className="text-xs">
                                    ↳ See posts from any time period.
                                  </FormDescription>
                                </div>
                              </div>
                            </RadioGroup>
                          </FormControl>
                        </FormItem>
                      )}
                    />
                  </div>

                  <Separator />

                  {/* Filter by Range Section */}
                  <div className="space-y-1.5 px-4">
                    <div>
                      <h3 className="text-sm font-medium">Filter by range.</h3>
                      <p className="mt-1.5 text-xs text-muted-foreground">
                        ↳ See posts from any time period.
                      </p>
                    </div>

                    <Controller
                      control={form.control}
                      name="dateRange"
                      render={({ field }) => (
                        <FormItem>
                          <FormControl>
                            <RadioGroup
                              value={field.value}
                              onValueChange={field.onChange}
                              disabled={isLoading}
                              className="gap-0.5"
                            >
                              {[
                                {
                                  value: "last_1_hour",
                                  label: "Last 1 hour",
                                },
                                {
                                  value: "last_24_hours",
                                  label: "Last 24 hours",
                                },
                                { value: "last_7_days", label: "Last 7 days" },
                                {
                                  value: "last_30_days",
                                  label: "Last 30 days",
                                },
                                {
                                  value: "last_365_days",
                                  label: "Last 365 days",
                                },
                              ].map((option) => (
                                <div
                                  key={option.value}
