"use client";

import React, { useState } from "react";
import Image from "next/image";
import {
  Carousel,
  CarouselContent,
  CarouselItem,
} from "@/shared/ui/components/Carousel";
import { AspectRatio } from "@/shared/ui/components/AspectRatio";
import { Button } from "@/shared/ui/components/Button";
import VideoPlayer from "../../../landing/ui/components/VideoPlayer";
import MediaViewerDrawer from "./MediaViewerDrawer";
import { TweetMediaThumbnails } from "./TweetMediaThumbnails";
import { Media } from "@/features/threads/types";

interface TweetMediaProps {
  media: Media[];
}

const TweetMedia: React.FC<TweetMediaProps> = ({ media }) => {
  if (!media || media.length === 0) return null;

  const uniqueMedia = media.filter(
    (item, index, self) =>
      index === self.findIndex((m) => m.id_str === item.id_str)
  );

  // Compute a standard aspect ratio from the first unique media item.
  let aspectRatio = 16 / 9; // fallback ratio
  const firstMedia = uniqueMedia[0];
  if (firstMedia) {
    if (firstMedia.original_info) {
      aspectRatio =
        firstMedia.original_info.width / firstMedia.original_info.height;
    } else if (firstMedia.sizes && firstMedia.sizes.large) {
      aspectRatio = firstMedia.sizes.large.w / firstMedia.sizes.large.h;
    }
  }

  // Compute a standard aspect ratio from the first unique media item.
  // let aspectRatio = 16 / 9; // fallback ratioS
  // const firstMedia = uniqueMedia[0];
  // if (firstMedia && firstMedia.original_info) {
  //   aspectRatio =
  //     firstMedia.original_info.width / firstMedia.original_info.height;
  // }

  // State for the "View All" drawer
  const [drawerOpen, setDrawerOpen] = useState(false);
  const [initialIndex, setInitialIndex] = useState(0);

  const renderMediaItem = (item: any) => {
    if (item.type === "video" || item.type === "animated_gif") {
      const variants = item.video_info?.variants || [];
      const hlsVariant = variants.find(
        (v: any) => v.content_type === "application/x-mpegURL"
      );
      const mp4Variants = variants.filter(
        (v: any) => v.content_type === "video/mp4"
      );
      const mp4Variant = mp4Variants.reduce(
        (prev: any, curr: any) =>
          (prev.bitrate || 0) > (curr.bitrate || 0) ? prev : curr,
        {}
      );
      return (
        <VideoPlayer
          hlsUrl={hlsVariant?.url}
          mp4Url={mp4Variant?.url}
          ariaLabel="Tweet video"
          className="rounded-lg border border-border"
        />
      );
    } else if (item.type === "photo") {
      return (
        <Image
          src={item?.media_url_https}
          alt={item?.ext_alt_text || "Tweet image"}
          fill
          className="rounded-lg border border-border object-cover"
          loading="eager"
          unoptimized={item?.media_url_https.includes("9jnl6fmpas.ufs.sh")}
        />
      );
    }
    return null;
  };

  // Render a simple view if there's only one unique media item.
  if (uniqueMedia.length === 1) {
    return (
      <AspectRatio ratio={aspectRatio}>
        {renderMediaItem(uniqueMedia[0])}
      </AspectRatio>
    );
  }

  // More than one unique media item: render a Carousel with a "View All" button.
  return (
    <div>
      <Carousel className="overflow-x-hidden rounded-lg">
        <CarouselContent>
          {uniqueMedia.map((item, index) => (
            <CarouselItem key={item.id_str || index}>
              <AspectRatio ratio={aspectRatio}>
                {renderMediaItem(item)}
              </AspectRatio>
            </CarouselItem>
          ))}
        </CarouselContent>
      </Carousel>
      <div className="mt-2 flex items-center gap-1">
        <TweetMediaThumbnails
          media={uniqueMedia}
          currentIndex={0}
          variant="tweet"
        />
        <Button
          onClick={() => {
            setInitialIndex(0);
            setDrawerOpen(true);
          }}
          variant="ghost"
          size="sm"
        >
          View All
        </Button>
      </div>
      <MediaViewerDrawer
        open={drawerOpen}
        onOpenChange={setDrawerOpen}
        media={uniqueMedia}
        initialIndex={initialIndex}
      />
    </div>
  );
};

export { TweetMedia };

"use client";

import React from "react";
import Image from "next/image";
import { cn } from "@/shared/lib/utils/utils";

export interface TweetMediaThumbnailsProps {
  media: any[];
  currentIndex?: number;
  onThumbnailClick?: (index: number) => void;
  className?: string;
  variant?: "tweet" | "drawer";
}

export const TweetMediaThumbnails: React.FC<TweetMediaThumbnailsProps> = ({
  media,
  currentIndex = 0,
  onThumbnailClick,
  className,
  variant = "tweet",
}) => {
  if (!media || media.length === 0) return null;

  // Deduplicate media items based on their unique id_str.
  const dedupedMedia = media.filter(
    (item, index, self) =>
      index === self.findIndex((m) => m.id_str === item.id_str)
  );

  const isTweet = variant === "tweet";
  const isDrawer = variant === "drawer";

  // In "tweet" mode, show only the first 2 thumbnails.
  const thumbnailsToShow = isTweet ? dedupedMedia.slice(0, 2) : dedupedMedia;
  const remainingCount = isTweet
    ? dedupedMedia.length - thumbnailsToShow.length
    : 0;

  return (
    <div className={cn("flex items-center gap-2", className)}>
      {thumbnailsToShow.map((item, index) => {
        // For video/animated GIF, use the provided thumbnail if available.
        const thumbnailUrl =
          (item.type === "video" || item.type === "animated_gif") &&
          item.thumbnails &&
          Array.isArray(item.thumbnails) &&
          item.thumbnails.length > 0
            ? item.thumbnails[0].url
            : item.media_url_https;

        // In drawer mode, highlight the active thumbnail.
        const isActive = isDrawer && currentIndex === index;

        // Build class names based on the variant.
        const thumbnailClasses = cn(
          "relative h-8 w-8 rounded duration-100",
          isDrawer
            ? // Drawer variant: add padding, clickable, and a ring that is 1px (or 2px if active).
              cn(
                "p-0.5 cursor-pointer hover:opacity-80",
                isActive ? "ring-2 ring-primary" : "ring-[1px] ring-border"
              )
            : // Tweet variant: non-clickable, and a 4px ring with 'ring-main'.
              "cursor-default ring-4 ring-main",
          // In tweet variant, apply a negative left margin to all but the first thumbnail.
          isTweet && index > 0 && "ml-[-8px]"
        );

        return (
          <div
            key={item.id_str || index}
            className={thumbnailClasses}
            onClick={
              isDrawer && onThumbnailClick
                ? () => onThumbnailClick(index)
                : undefined
            }
          >
            <Image
              src={thumbnailUrl}
              alt={item.ext_alt_text || "Tweet media"}
              width={32}
              height={32}
              className="h-full w-full rounded-[2px] object-cover"
            />
          </div>
        );
      })}
      {/* In tweet variant, show the +X badge if there are more thumbnails. */}
      {isTweet && remainingCount > 0 && (
        <div
          className={cn(
            "z-10 flex h-8 w-8 cursor-default items-center justify-center rounded bg-muted font-mono text-xs font-medium",
            "ml-[-8px]",
            "ring-4 ring-main"
          )}
        >
          +{remainingCount}
        </div>
      )}
    </div>
  );
};

"use client";

import { useQuery, useAction } from "convex/react";
import { api } from "@/convex/_generated/api";
import { useState, useEffect } from "react";
import { logger } from "@/shared/lib/logger";
import { WaitlistUser } from "../types";

export function useWaitlistUsers() {
  const twitterHandles = useQuery(api.waitlist.getTwitterHandles);
  const totalCount = useQuery(api.waitlist.getWaitlistCount);
  const getTwitterProfile = useAction(api.socialapi.getTwitterProfile);
  const [profiles, setProfiles] = useState<WaitlistUser[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchProfiles = async () => {
      if (twitterHandles === undefined) return; // Wait for data
      if (twitterHandles.length === 0) {
        setProfiles([]);
        setLoading(false);
        return;
      }
      try {
        const profilePromises = twitterHandles.map((twitter) =>
          getTwitterProfile({ twitter }).catch((error) => {
            logger.error(`Error fetching ${twitter}:`, error);
            return null;
          })
        );
        const results = await Promise.all(profilePromises);
        const validProfiles = results
          .filter((p): p is any => p !== null)
          .map((p) => ({
            profile_image_url_https: p.profile_image_url_https,
            name: p.name,
            screen_name: p.screen_name,
            verified: Boolean(p.verified),
          })) as WaitlistUser[];
        setProfiles(validProfiles);
      } catch (error) {
        logger.error("Unexpected error fetching profiles:", error);
      } finally {
        setLoading(false);
      }
    };
    fetchProfiles();
  }, [twitterHandles, getTwitterProfile]);

  return {
    profiles,
    loading,
    totalCount: totalCount ?? 0,
    isCountLoading: totalCount === undefined,
  };
}
